def get_svg_icon(name, size="24px", color="currentColor", class_name=""):
    """
    Get SVG icon as HTML
    
    Args:
        name: Icon name
        size: Icon size (e.g., "24px", "2rem")
        color: Icon color
        class_name: CSS class name
    
    Returns:
        HTML string with SVG
    """
    svg = ICONS.get(name, '')
    if not svg:
        return f'<span class="icon-undefined">[{name}]</span>'
    
    return f'''
    <span class="svg-icon {class_name}" style="display: inline-block; width: {size}; height: {size}; color: {color}; vertical-align: -0.125em;">
        {svg}
    </span>
    '''
